class Solution:
    def largestPerimeter(self, nums):
        best = 0
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                for k in range(j + 1, n):
                    a, b, c = sorted((nums[i], nums[j], nums[k]))
                    if a + b > c:
                        best = max(best, a + b + c)
        return best

